import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { authAPI, progressAPI } from '../services/api';
import { useLanguage } from '../contexts/LanguageContext';

const Dashboard = () => {
  const navigate  = useNavigate();
  const { language, changeLanguage } = useLanguage();

  const [user, setUser]       = useState(null);
  const [stats, setStats]     = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => { fetchData(); }, [language]);

  const fetchData = async () => {
    setLoading(true);
    try {
      // Fetch user profile + both progress types in parallel
      const [profileRes, lessonRes, practiceRes] = await Promise.allSettled([
        authAPI.getDashboard(),
        progressAPI.getLessonProgress(language),
        progressAPI.getPracticeProgress(language),
      ]);

      if (profileRes.status === 'fulfilled') setUser(profileRes.value.data);

      const lessonData   = lessonRes.status   === 'fulfilled' ? (lessonRes.value.data   || []) : [];
      const practiceData = practiceRes.status === 'fulfilled' ? (practiceRes.value.data || []) : [];

      // ── Compute lesson stats ──────────────────────────────
      const lessonsCompleted = lessonData.length;
      const bestWpm  = lessonData.length > 0
        ? Math.max(...lessonData.map(p => p.bestWPM || p.wpm || 0))
        : 0;
      const avgAccuracy = lessonData.length > 0
        ? Math.round(lessonData.reduce((s, p) => s + (p.bestAccuracy || p.accuracy || 0), 0) / lessonData.length)
        : 0;

      // ── Compute practice stats ────────────────────────────
      const practicesCompleted = practiceData.length;
      const bestPracticeWpm = practiceData.length > 0
        ? Math.max(...practiceData.map(p => p.wpm || 0))
        : 0;
      const totalTimeMin = practiceData.length > 0
        ? practiceData.reduce((s, p) => s + (p.duration || 0), 0)
        : 0;

      setStats({
        lessonsCompleted,
        bestWpm: Math.max(bestWpm, bestPracticeWpm),
        avgAccuracy,
        practicesCompleted,
        totalTimeMin,
      });
    } catch (err) {
      console.error('Dashboard fetch error:', err);
    } finally {
      setLoading(false);
    }
  };

  const statCards = stats ? [
    { label: 'Lessons Done',     value: stats.lessonsCompleted,  color: '#2563eb', icon: '📖' },
    { label: 'Best WPM',         value: stats.bestWpm,           color: '#16a34a', icon: '⚡' },
    { label: 'Avg Accuracy',     value: stats.avgAccuracy ? `${stats.avgAccuracy}%` : '—', color: '#d97706', icon: '✓' },
    { label: 'Practice Sessions',value: stats.practicesCompleted,color: '#7c3aed', icon: '🏋️' },
  ] : [];

  return (
    <div style={{ minHeight: '100vh', padding: '24px 32px' }}>

      {/* ── Welcome ── */}
      <div style={{ marginBottom: 24 }}>
        <h2 style={{ fontSize: 22, fontWeight: 600, color: '#fff', margin: 0 }}>
          {loading ? 'Loading…' : `Welcome back${user?.name ? ', ' + user.name : ''}!`}
        </h2>
        <p style={{ color: 'rgba(255,255,255,0.7)', margin: '4px 0 0', fontSize: 14 }}>
          {language === 'punjabi' ? 'ਪੰਜਾਬੀ' : 'English'} mode · Keep practising every day
        </p>
      </div>

      {/* ── Stat cards ── */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit,minmax(160px,1fr))', gap: 12, marginBottom: 28 }}>
        {loading ? (
          [1,2,3,4].map(i => (
            <div key={i} style={{ background: 'rgba(255,255,255,0.1)', borderRadius: 12, height: 90, animation: 'pulse 1.5s infinite' }} />
          ))
        ) : statCards.map(s => (
          <div key={s.label} style={{
            background: '#fff', borderRadius: 12, padding: '16px 18px',
            display: 'flex', flexDirection: 'column', gap: 4,
          }}>
            <div style={{ fontSize: 20 }}>{s.icon}</div>
            <div style={{ fontSize: 26, fontWeight: 700, color: s.color, lineHeight: 1 }}>
              {s.value}
            </div>
            <div style={{ fontSize: 11, color: '#94a3b8', fontWeight: 500, textTransform: 'uppercase', letterSpacing: '.04em' }}>
              {s.label}
            </div>
          </div>
        ))}
      </div>

      {/* ── Mode buttons ── */}
      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 14, maxWidth: 640 }}>
        {[
          { label: 'Learn', sub: 'Chapters & structured lessons', color: '#2563eb', bg: '#dbeafe', route: '/learn', icon: '📚' },
          { label: 'Practice', sub: 'Timed drills by difficulty', color: '#16a34a', bg: '#dcfce7', route: '/practice', icon: '⏱️' },
        ].map(m => (
          <div key={m.label} onClick={() => navigate(m.route)}
            style={{
              background: '#fff', borderRadius: 14, padding: '20px 22px', cursor: 'pointer',
              borderTop: `3px solid ${m.color}`, transition: 'transform .15s',
            }}
            onMouseEnter={e => e.currentTarget.style.transform='translateY(-2px)'}
            onMouseLeave={e => e.currentTarget.style.transform='translateY(0)'}
          >
            <div style={{ fontSize: 24, marginBottom: 6 }}>{m.icon}</div>
            <div style={{ fontWeight: 600, fontSize: 16, color: '#1e293b', marginBottom: 3 }}>{m.label}</div>
            <div style={{ fontSize: 12, color: '#64748b' }}>{m.sub}</div>
          </div>
        ))}
      </div>

      {/* ── Language switcher ── */}
      <div style={{ marginTop: 24, display: 'flex', gap: 8 }}>
        {['english','punjabi'].map(lang => (
          <button key={lang} onClick={() => changeLanguage(lang)}
            style={{
              padding: '6px 16px', borderRadius: 20, border: 'none', cursor: 'pointer',
              background: language === lang ? '#fff' : 'rgba(255,255,255,0.2)',
              color: language === lang ? '#1e293b' : '#fff',
              fontWeight: language === lang ? 600 : 400, fontSize: 13,
            }}>
            {lang === 'english' ? '🇬🇧 English' : '🇮🇳 ਪੰਜਾਬੀ'}
          </button>
        ))}
      </div>
    </div>
  );
};

export default Dashboard;
